"use client";

import Image from "next/image";
import AppStoreButtons from "./AppStoreButtons";
import Reveal from "./Reveal";
import { StaggerContainer, StaggerItem } from "./Reveal";

const bullets = [
  "Designed for everyday wear",
  "Works with African and global fashion",
  "No pressure to buy more clothes",
];

const gallery = [
  { src: "/images/gallery-1.png", alt: "Young African man in navy suit" },
  { src: "/images/gallery-2.png", alt: "Person in orange sweater with green beanie and sunglasses" },
  { src: "/images/gallery-3.png", alt: "African woman in blue-red print dress" },
  { src: "/images/gallery-4.png", alt: "Stylish fashion look" },
];

export default function BuiltForReal() {
  return (
    <section id="built-for-real" className="py-8 md:py-12">
      <div className="max-w-[1248px] mx-auto px-6 lg:px-12">
        <div className="bg-section-warm rounded-[32px] py-10 md:py-14">
          {/* Text content */}
          <div className="px-8 md:px-12 pb-12">
            <Reveal>
              <h2 className="font-heading text-3xl md:text-4xl lg:text-[44px] font-semibold text-foreground leading-tight">
                Built for real people, real wardrobes.
              </h2>
            </Reveal>

            <Reveal delay={0.1}>
              <ul className="mt-6 space-y-2">
                {bullets.map((bullet, i) => (
                  <li key={i} className="flex items-center gap-3 text-sm text-muted-foreground">
                    <span className="w-1.5 h-1.5 rounded-full bg-foreground flex-shrink-0" />
                    {bullet}
                  </li>
                ))}
              </ul>
            </Reveal>

            <Reveal delay={0.2}>
              <div className="mt-8">
                <AppStoreButtons />
              </div>
            </Reveal>
          </div>

          {/* Gallery */}
          <div className="px-8 md:px-12 pb-4">
            <StaggerContainer className="grid grid-cols-2 md:grid-cols-4 gap-4" staggerDelay={0.1}>
              {gallery.map((img, i) => (
                <StaggerItem key={i}>
                  <div className="relative aspect-[3/4] overflow-hidden rounded-xl">
                    <Image
                      src={img.src}
                      alt={img.alt}
                      fill
                      className="object-cover"
                      sizes="(max-width: 768px) 50vw, 25vw"
                    />
                  </div>
                </StaggerItem>
              ))}
            </StaggerContainer>
          </div>
        </div>
      </div>
    </section>
  );
}

"use client";

import Image from "next/image";
import { useEffect, useRef, useState } from "react";
import AppStoreButtons from "./AppStoreButtons";
import Reveal from "./Reveal";
import { StaggerContainer, StaggerItem } from "./Reveal";

const bullets = [
	"Designed for everyday wear",
	"Works with African and global fashion",
	"No pressure to buy more clothes",
];

const gallery = [
	{ src: "/images/gallery-1.png", alt: "Young African man in navy suit" },
	{
		src: "/images/gallery-2.png",
		alt: "Person in orange sweater with green beanie and sunglasses",
	},
	{ src: "/images/gallery-3.png", alt: "African woman in blue-red print dress" },
	{ src: "/images/gallery-4.png", alt: "Stylish fashion look" },
];

export default function BuiltForReal() {
	const sectionRef = useRef<HTMLElement | null>(null);
	const [highlight, setHighlight] = useState(false);

	useEffect(() => {
		const section = sectionRef.current;
		if (!section) return undefined;

		let timeoutId: ReturnType<typeof setTimeout> | null = null;
		const observer = new IntersectionObserver(
			([entry]) => {
				if (!entry?.isIntersecting) return;
				setHighlight(true);
				if (timeoutId) clearTimeout(timeoutId);
				timeoutId = setTimeout(() => setHighlight(false), 1500);
			},
			{ threshold: 0.35 }
		);

		observer.observe(section);
		return () => {
			observer.disconnect();
			if (timeoutId) clearTimeout(timeoutId);
		};
	}, []);

	return (
		<section id="built-for-real" ref={sectionRef} className="py-8 md:py-12">
			<div className="max-w-[1248px] mx-auto px-6 lg:px-12">
				<div className="bg-section-warm rounded-[32px] py-10 md:py-14">
					{/* Text content */}
					<div className="px-8 md:px-12 pb-12">
						<Reveal>
							<h2 className="font-heading text-3xl md:text-4xl lg:text-[44px] font-semibold text-foreground leading-tight">
								Built for real people, real wardrobes.
							</h2>
						</Reveal>

						<Reveal delay={0.1}>
							<ul className="mt-6 space-y-2">
								{bullets.map((bullet, i) => (
									<li
										key={i}
										className="flex items-center gap-3 text-sm text-muted-foreground"
									>
										<span className="w-1.5 h-1.5 rounded-full bg-foreground flex-shrink-0" />
										{bullet}
									</li>
								))}
							</ul>
						</Reveal>

						<Reveal delay={0.2}>
							<div
								className={`mt-8 inline-block rounded-[28px] transition-all duration-300 ${
									highlight
										? "ring-2 ring-warm-accent/60 ring-offset-4 ring-offset-background"
										: ""
								}`}
							>
								<AppStoreButtons />
							</div>
						</Reveal>
					</div>

					{/* Gallery */}
					<div className="px-8 md:px-12 pb-4">
						<StaggerContainer
							className="grid grid-cols-2 md:grid-cols-4 gap-4"
							staggerDelay={0.1}
						>
							{gallery.map((img, i) => (
								<StaggerItem key={i}>
									<div className="relative aspect-[3/4] overflow-hidden rounded-xl">
										<Image
											src={img.src}
											alt={img.alt}
											fill
											className="object-cover"
											sizes="(max-width: 768px) 50vw, 25vw"
										/>
									</div>
								</StaggerItem>
							))}
						</StaggerContainer>
					</div>
				</div>
			</div>
		</section>
	);
}

"use client";

import { useState } from "react";
import Image from "next/image";
import Link from "next/link";

const navLinks = [
  { label: "How it works", href: "/#how-it-works" },
  { label: "Benefits", href: "/#features" },
  { label: "FAQ", href: "/#faq" },
  { label: "Team", href: "/team" },
];

export default function Navbar() {
  const [menuOpen, setMenuOpen] = useState(false);

  return (
    <nav className="sticky top-0 z-50 bg-background/90 backdrop-blur-md border-b border-border">
      <div className="max-w-[1248px] mx-auto px-6 lg:px-12 flex items-center justify-between h-16">

        {/* Name + Slogan */}
      <Link href="/" className="justify-center items-center mt-2">
          <Image src="/images/name-slogan.png" alt="Closet Heritage" width={170} height={100} />
      </Link>


        {/* Desktop nav links */}
        <div className="hidden md:flex items-center gap-8">
          {navLinks.map((link) => (
            <a
              key={link.href}
              href={link.href}
              className="text-sm text-black hover:text-foreground transition-colors"
            >
              {link.label}
            </a>
          ))}
        </div>

        {/* Desktop CTAs */}
        <div className="hidden md:flex items-center gap-4">
          <Link href="/#footer" className="text-sm text-black hover:text-foreground transition-colors">
            Talk to us
          </Link>
          <a
            href="/#built-for-real"
            className="inline-flex items-center justify-center rounded-none h-10 px-4 text-sm bg-btn-cta text-foreground hover:bg-btn-cta-hover border border-border"
          >
            Get the app
          </a>
        </div>

        {/* Mobile hamburger */}
        <button
          className="md:hidden flex flex-col gap-1.5 p-2"
          onClick={() => setMenuOpen(!menuOpen)}
          aria-label="Toggle menu"
        >
          <span className={`block w-6 h-0.5 bg-foreground transition-transform ${menuOpen ? "rotate-45 translate-y-2" : ""}`} />
          <span className={`block w-6 h-0.5 bg-foreground transition-opacity ${menuOpen ? "opacity-0" : ""}`} />
          <span className={`block w-6 h-0.5 bg-foreground transition-transform ${menuOpen ? "-rotate-45 -translate-y-2" : ""}`} />
        </button>
      </div>

      {/* Mobile menu */}
      {menuOpen && (
        <div className="md:hidden border-t border-border bg-background px-6 py-4 space-y-4">
          {navLinks.map((link) => (
            <a
              key={link.href}
              href={link.href}
              className="block text-sm text-black hover:text-foreground"
              onClick={() => setMenuOpen(false)}
            >
              {link.label}
            </a>
          ))}
          <Link
            href="/#footer"
            className="block text-sm text-black hover:text-foreground"
            onClick={() => setMenuOpen(false)}
          >
            Talk to us
          </Link>
          <a
            href="/#built-for-real"
            className="inline-flex items-center justify-center rounded-none h-10 px-4 text-sm bg-btn-cta text-foreground hover:bg-btn-cta-hover border border-border w-full"
            onClick={() => setMenuOpen(false)}
          >
            Get the app
          </a>
         </div>
       )}
     </nav>
   );
}

"use client";

import { useCallback, useState } from "react";
import Image from "next/image";
import Link from "next/link";

const navLinks = [
  { label: "How it works", href: "/#how-it-works" },
  { label: "Benefits", href: "/#features" },
  { label: "FAQ", href: "/#faq" },
  { label: "Team", href: "/team" },
];

export default function Navbar() {
  const [menuOpen, setMenuOpen] = useState(false);
  const handleScrollToDownload = useCallback(() => {
    const target = document.getElementById("built-for-real");
    if (target) {
      target.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  }, []);

  return (
    <nav className="sticky top-0 z-50 bg-background/90 backdrop-blur-md border-b border-border">
      <div className="max-w-[1248px] mx-auto px-6 lg:px-12 flex items-center justify-between h-16">

        {/* Name + Slogan */}
      <Link href="/" className="justify-center items-center mt-2">
          <Image src="/images/name-slogan.png" alt="Closet Heritage" width={170} height={100} />
      </Link>


        {/* Desktop nav links */}
        <div className="hidden md:flex items-center gap-8">
          {navLinks.map((link) => (
            <a
              key={link.href}
              href={link.href}
              className="text-sm text-black hover:text-foreground transition-colors"
            >
              {link.label}
            </a>
          ))}
        </div>

        {/* Desktop CTAs */}
        <div className="hidden md:flex items-center gap-4">
          <Link href="/#footer" className="text-sm text-black hover:text-foreground transition-colors">
            Talk to us
          </Link>
          <Link
            href="/#built-for-real"
            onClick={handleScrollToDownload}
            className="inline-flex items-center justify-center rounded-none h-10 px-4 text-sm bg-btn-cta text-foreground hover:bg-btn-cta-hover border border-border"
          >
            Get the app
          </Link>
        </div>

        {/* Mobile hamburger */}
        <button
          className="md:hidden flex flex-col gap-1.5 p-2"
          onClick={() => setMenuOpen(!menuOpen)}
          aria-label="Toggle menu"
        >
          <span className={`block w-6 h-0.5 bg-foreground transition-transform ${menuOpen ? "rotate-45 translate-y-2" : ""}`} />
          <span className={`block w-6 h-0.5 bg-foreground transition-opacity ${menuOpen ? "opacity-0" : ""}`} />
          <span className={`block w-6 h-0.5 bg-foreground transition-transform ${menuOpen ? "-rotate-45 -translate-y-2" : ""}`} />
        </button>
      </div>

      {/* Mobile menu */}
      {menuOpen && (
        <div className="md:hidden border-t border-border bg-background px-6 py-4 space-y-4">
          {navLinks.map((link) => (
            <a
              key={link.href}
              href={link.href}
              className="block text-sm text-black hover:text-foreground"
              onClick={() => setMenuOpen(false)}
            >
              {link.label}
            </a>
          ))}
          <Link
            href="/#footer"
            className="block text-sm text-black hover:text-foreground"
            onClick={() => setMenuOpen(false)}
          >
            Talk to us
          </Link>
          <Link
            href="/#built-for-real"
            className="inline-flex items-center justify-center rounded-none h-10 px-4 text-sm bg-btn-cta text-foreground hover:bg-btn-cta-hover border border-border w-full"
            onClick={() => {
              setMenuOpen(false);
              handleScrollToDownload();
            }}
          >
            Get the app
          </Link>
         </div>
       )}
     </nav>
   );
}

/**
 * Invite-flow constants. Store URLs fall back to placeholders so that local
 * development doesn't 404 before the apps are published; update env vars
 * (`NEXT_PUBLIC_APP_STORE_URL`, `NEXT_PUBLIC_PLAY_STORE_URL`) once live.
 */

export const APP_SCHEME = "closet-heritage";

export const IOS_APP_STORE_URL =
  process.env.NEXT_PUBLIC_APP_STORE_URL ||
  // TODO: replace with real App Store URL once approved
  "https://apps.apple.com/app/closet-heritage/id0000000000";

export const ANDROID_PACKAGE = "com.closetheritage.app";

/**
 * Play Store URL. When a `code` is provided, Google's Install Referrer API
 * will surface `?referrer=code=<CODE>` in the installed app on first launch —
 * this is what `app/index.tsx` picks up to auto-apply referral codes on
 * deferred Android installs.
 */
export function buildPlayStoreUrl(code?: string): string {
  const base = `https://play.google.com/store/apps/details?id=${ANDROID_PACKAGE}`;
  if (!code) return base;
  const referrer = encodeURIComponent(`code=${code}`);
  return `${base}&referrer=${referrer}`;
}

export function buildAppScheme(code: string): string {
  return `${APP_SCHEME}://invite/${code}`;
}

const CODE_REGEX = /^[A-Z0-9_-]{3,32}$/;

export function normalizeCode(raw: string): string | null {
  const upper = raw.trim().toUpperCase();
  return CODE_REGEX.test(upper) ? upper : null;
}

